package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDirectory = new File("uploads").getCanonicalFile

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    val requestedFile = new File(baseDirectory, filename).getCanonicalFile

    if (!requestedFile.getPath.startsWith(baseDirectory.getPath)) {
      Forbidden("Access denied.")
    } else if (!requestedFile.exists() || !requestedFile.isFile) {
      NotFound("File not found.")
    } else {
      val source = Source.fromFile(requestedFile)
      try {
        Ok(source.mkString).as("text/plain")
      } finally {
        source.close()
      }
    }
  }
}